class_name StateMachine
extends Node

@export var initial_state: Node

var current_state: Node
var states: Dictionary = {}

func _ready() -> void:
	# 直接初始化，不使用 await（避免 coroutine 被 GC）
	for child in get_children():
		var is_state = child is State or child.has_method("enter")
		print("   - 子节点: ", child.name, ", 脚本: ", child.get_script(), ", is State: ", is_state)
		if is_state:
			states[child.name.to_lower()] = child
			if child.has_signal("transitioned") and not child.transitioned.is_connected(on_child_transition):
				child.transitioned.connect(on_child_transition)
			child.set("entity", owner)
			print("     ✅ 已注册状态: ", child.name)

	if initial_state:
		current_state = initial_state
		print("🔍 StateMachine: 使用 initial_state: ", current_state.name)
	else:
		# 自动使用第一个 State 子节点作为初始状态
		for child in get_children():
			if child is State or child.has_method("enter"):
				current_state = child
				print("🔍 StateMachine: 自动使用首个状态: ", current_state.name)
				break

	if not current_state:
		print("❌ StateMachine: 没有找到任何状态！")
		return

	if current_state:
		current_state.enter()
		print("🔍 StateMachine: 已进入初始状态: ", current_state.name)

	# 确保 Camera2D 是当前相机
	var cam = owner.get_node_or_null("Camera2D") if owner else null
	if cam and cam is Camera2D:
		cam.enabled = true

func _process(delta: float) -> void:
	if current_state:
		current_state.update(delta)

func _physics_process(delta: float) -> void:
	if current_state:
		current_state.physics_update(delta)

func on_child_transition(state: Node, new_state_name: String) -> void:
	if state != current_state:
		return

	var new_state = states.get(new_state_name.to_lower())
	if not new_state:
		printerr("StateMachine: State '%s' does not exist." % new_state_name)
		return

	if current_state:
		current_state.exit()

	new_state.enter()
	current_state = new_state

## 强制切换到指定状态（用于外部触发）
func transition_to(state_name: String) -> void:
	var new_state = states.get(state_name.to_lower())
	if not new_state:
		printerr("StateMachine: State '%s' does not exist." % state_name)
		return

	if current_state:
		current_state.exit()

	new_state.enter()
	current_state = new_state

Content of res://entities/enemy/enemy.gd:
extends CharacterBody2D
class_name Enemy

## 属性
@export var max_hp: int = 30
@export var move_speed: float = 120.0
@export var detect_range: float = 200.0
@export var attack_range: float = 30.0
@export var attack_damage: int = 8
@export var attack_cooldown: float = 1.0

var hp: int = 30
var player: Player = null
var attack_ready: bool = true

signal died

func _ready() -> void:
	hp = max_hp
	_setup_collision()
	_setup_state_machine()
	call_deferred("_find_player")

## 确保状态机的 entity 指向自己（运行时 owner 可能为 null）
func _setup_state_machine() -> void:
	var sm = $StateMachine
	if not sm.get_script():
		# StateMachine 无脚本，手动管理（备用）
		return
	# StateMachine._ready() 已经用 owner 设置了 entity
	# 但运行时 owner 可能为 null，手动补救
	for child in sm.get_children():
		if child.has_method("enter") and child.get("entity") == null:
			child.set("entity", self)

func _find_player() -> void:
	player = get_tree().get_first_node_in_group("player") as Player
	if not player:
		# 重试
		await get_tree().create_timer(0.5).timeout
		_find_player()

func _setup_collision() -> void:
	var shape_node = $CollisionShape2D
	if shape_node and shape_node.shape == null:
		var circle = CircleShape2D.new()
		circle.radius = 14.0
		shape_node.shape = circle

## 获取到玩家的方向
func get_player_direction() -> Vector2:
	if not player:
		return Vector2.ZERO
	return (player.global_position - global_position).normalized()

## 到玩家的距离
func distance_to_player() -> float:
	if not player:
		return INF
	return global_position.distance_to(player.global_position)

## 被攻击
func take_damage(amount: int) -> void:
	hp = max(0, hp - amount)
	print("👹 敌人受到伤害: ", amount, " 剩余HP: ", hp)
	if hp <= 0:
		died.emit()
		queue_free()

## 执行攻击
func perform_attack() -> void:
	if not attack_ready or not player:
		return
	attack_ready = false
	player.take_damage(attack_damage)
	print("👹 敌人攻击玩家，伤害: ", attack_damage)
	await get_tree().create_timer(attack_cooldown).timeout
	attack_ready = true

