## 属性加成（在 BuffManager 中应用）
## 格式: { "max_hp": 20, "atk": 5, "move_speed": 10 }
@export var stat_modifiers: Dictionary = {}

## 百分比属性加成（如 {"atk": 0.1} = +10% 攻击力）
