{"content": "class_name Buff
extends Resource
## Buff/被动效果 — 可被装备、技能、消耗品等任何系统复用
##
## duration = 0 表示永久（装备类 Buff）
## tick_interval = 0 表示不触发 tick

## 显示名称
@export var display_name: String = ""

## 图标
@export var icon: Texture2D

## 持续时间（秒，0=永久）
@export var duration: float = 0.0

## tick 间隔（秒，0=不触发）
@export var tick_interval: float = 0.0

## 属性加成（固定值）
@export var stat_modifiers: Dictionary = {}

## 属性百分比加成
@export var stat_multipliers: Dictionary = {}

## tick 时回复 HP
@export var tick_heal: int = 0


## 应用此 Buff 到目标实体
func apply_to(entity: Node) -> void:
	if not entity:
		return
	for stat in stat_modifiers:
		_apply_stat(entity, stat, stat_modifiers[stat])


## 从目标实体移除此 Buff
func remove_from(entity: Node) -> void:
	if not entity:
		return
	for stat in stat_modifiers:
		_apply_stat(entity, stat, -stat_modifiers[stat])


## 应用单个属性修改
func _apply_stat(entity: Node, stat: String, amount: float) -> void:
	if stat in entity:
		entity.set(stat, entity.get(stat) + amount)
", "path": "res://items/buff.gd"}

{"content": "class_name BuffManager
extends Node
## Buff 管理器 — 挂载到 Player 节点，管理所有激活的 Buff
##
## 装备、技能、消耗品等任何系统都通过 BuffManager 施加/移除效果

## 当前激活的所有 Buff
var _active_buffs: Array[Buff] = []

## 定时器引用
var _tick_timer: float = 0.0


func _process(delta: float) -> void:
	if _active_buffs.is_empty():
		return
	_tick_timer += delta
	if _tick_timer >= 1.0:
		_tick_timer -= 1.0
		_tick_buffs()


func _tick_buffs() -> void:
	var entity = get_parent()
	for buff in _active_buffs:
		if buff.tick_interval > 0 and buff.tick_heal > 0:
			if entity.has_method("heal"):
				entity.heal(buff.tick_heal)


## 施加 Buff（装备、技能等调用）
func apply_buff(buff: Buff) -> void:
	if not buff:
		return
	buff.apply_to(get_parent())
	_active_buffs.append(buff)
	print("🟢 BuffManager: 施加 %s" % buff.display_name)


## 移除 Buff
func remove_buff(buff: Buff) -> void:
	if not buff or not buff in _active_buffs:
		return
	buff.remove_from(get_parent())
	_active_buffs.erase(buff)
	print("🔴 BuffManager: 移除 %s" % buff.display_name)


## 移除所有 Buff（死亡/重置时）
func clear_all() -> void:
	for buff in _active_buffs:
		buff.remove_from(get_parent())
	_active_buffs.clear()
", "path": "res://items/buff_manager.gd"}

{"content": "class_name Inventory
extends Resource
## 背包系统 — 可存储任意 ItemData + 数量的网格

## 背包容量
@export var capacity: int = 20

## 物品槽位数组（索引 → {item: ItemData, quantity: int}）
var _slots: Array[Dictionary] = []


func _init() -> void:
	_slots.resize(capacity)
	for i in range(capacity):
		_slots[i] = {"item": null, "quantity": 0}


## 添加物品（返回成功数量，0=背包满）
func add_item(item: ItemData, quantity: int = 1) -> int:
	var added = 0
	var remaining = quantity

	# 先尝试堆叠到已有槽位
	if item.stackable:
		for i in range(capacity):
			var slot = _slots[i]
			if slot.item == item and slot.quantity < item.max_stack:
				var space = item.max_stack - slot.quantity
				var to_add = min(space, remaining)
				slot.quantity += to_add
				remaining -= to_add
				added += to_add
				if remaining <= 0:
					return added

	# 填到空槽位
	for i in range(capacity):
		var slot = _slots[i]
		if slot.item == null:
			var to_add = min(item.max_stack if item.stackable else 1, remaining)
			slot.item = item
			slot.quantity = to_add
			remaining -= to_add
			added += to_add
			if remaining <= 0:
				return added

	return added


## 移除物品
func remove_item(item: ItemData, quantity: int = 1) -> int:
	var removed = 0
	for i in range(capacity - 1, -1, -1):
		var slot = _slots[i]
		if slot.item == item:
			var to_remove = min(quantity - removed, slot.quantity)
			slot.quantity -= to_remove
			removed += to_remove
			if slot.quantity <= 0:
				slot.item = null
				slot.quantity = 0
			if removed >= quantity:
				return removed
	return removed


## 获取指定槽位
func get_slot(index: int) -> Dictionary:
	if index >= 0 and index < capacity:
		return _slots[index]
	return {"item": null, "quantity": 0}


## 获取物品总数量
func get_item_count(item: ItemData) -> int:
	var count = 0
	for slot in _slots:
		if slot.item == item:
			count += slot.quantity
	return count


## 是否有足够空间
func has_space(item: ItemData, quantity: int = 1) -> bool:
	var space = 0
	if item.stackable:
		for slot in _slots:
			if slot.item == item:
				space += item.max_stack - slot.quantity
	for slot in _slots:
		if slot.item == null:
			space += item.max_stack if item.stackable else 1
	return space >= quantity
", "path": "res://items/inventory.gd"}
